#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
#define ls(x) (x<<1)
#define rs(x) (x<<1|1)
using NP std;
CI mxx=1e5+100;
int t1[4*mxx],t2[4*mxx];
int n,m,t;
void pu(int q,int tr[])
{
	tr[q]=tr[ls(q)]+tr[rs(q)];
}
void up(int q,int l,int r,int p,int v,int tr[])
{
	if(l==r)
	{
		tr[q]+=v;
		return;
	}
	int md=(l+r)>>1;
	if(p<=md)up(ls(q),l,md,p,v,tr);
	else up(rs(q),md+1,r,p,v,tr);
	pu(q,tr);
}
int qry(int q,int l,int r,int ql,int qr,int tr[])
{
	if(ql>qr)return 0;
	if(l>=ql&&r<=qr)return tr[q];
	int md=(l+r)>>1,res=0;
	if(ql<=md)res+=qry(ls(q),l,md,ql,qr,tr);
	if(qr>md)res+=qry(rs(q),md+1,r,ql,qr,tr);
	return res;
}
int qp(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
signed main(void)
{
	IOS
	cin.tie(0);
	cin>>n>>m;
	t=0;
	int op,l,r;
	wh(m--)
	{
		cin>>op>>l>>r;
		if(op==1)
		{
			t++;
			up(1,1,n,r,1,t1);
			up(1,1,n,l,1,t2);
		}
		else
		{
			int c1=qry(1,1,n,1,l-1,t1);
			int c2=qry(1,1,n,r+1,n,t2);
			cout<<t-c1-c2<<'\n';
		}
	}
	return 0;
}
